  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../lib/generated/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n///////////////////////\n// 👤 USERS\n///////////////////////\nmodel User {\n  id        String   @id @default(cuid())\n  name      String\n  email     String   @unique\n  password  String?\n  createdAt DateTime @default(now())\n\n  orders  Order[]\n  reviews Review[]\n}\n\n///////////////////////\n// 📂 CATEGORIES\n///////////////////////\nmodel Category {\n  id        String   @id @default(cuid())\n  name      String\n  slug      String   @unique\n  icon      String?\n  createdAt DateTime @default(now())\n\n  products Product[]\n}\n\n///////////////////////\n// 🛍️ PRODUCTS\n///////////////////////\nmodel Product {\n  id          String   @id @default(cuid())\n  title       String\n  slug        String   @unique\n  description String\n  price       Float\n  discount    Float?\n  stock       Int      @default(0)\n  createdAt   DateTime @default(now())\n\n  offerTag         String?\n  tripleTreatAlert String?\n  countdownExpiry  DateTime?\n  specifications   Json?\n  deliveryEstimate String?\n  badges           String[]\n  imageUrls        String[]\n\n  relatedProductIds String[]   @default([])\n  categories        Category[]\n\n  images     ProductImage[]\n  details    ProductDetail[]\n  reviews    Review[]\n  orderItems OrderItem[]\n}\n\n///////////////////////\n// 🖼️ PRODUCT IMAGES\n///////////////////////\nmodel ProductImage {\n  id        String @id @default(cuid())\n  url       String\n  productId String\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n}\n\n///////////////////////\n// 📄 PRODUCT DETAILS\n///////////////////////\nmodel ProductDetail {\n  id        String @id @default(cuid())\n  label     String\n  value     String\n  productId String\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n}\n\n///////////////////////\n// ⭐ REVIEWS\n///////////////////////\nmodel Review {\n  id        String   @id @default(cuid())\n  rating    Int\n  comment   String\n  createdAt DateTime @default(now())\n\n  userId    String\n  productId String\n\n  user    User    @relation(fields: [userId], references: [id])\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n}\n\n///////////////////////\n// 🛒 ORDERS\n///////////////////////\nmodel Order {\n  id        String   @id @default(cuid())\n  total     Float\n  status    String   @default(\"pending\")\n  createdAt DateTime @default(now())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  items   OrderItem[]\n  address Address?\n\n  paymentId         String? // Razorpay Payment ID\n  shiprocketOrderId String? // Shiprocket Order ID\n  shipmentStatus    String? // Shiprocket Status\n\n  affiliateId String?\n  affiliate   Affiliate? @relation(fields: [affiliateId], references: [id])\n}\n\n///////////////////////\n// 📦 ORDER ITEMS\n///////////////////////\nmodel OrderItem {\n  id       String @id @default(cuid())\n  quantity Int\n  price    Float\n\n  orderId   String\n  productId String\n\n  order   Order   @relation(fields: [orderId], references: [id])\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n}\n\n///////////////////////\n// 🤝 AFFILIATES\n///////////////////////\nmodel Affiliate {\n  id             String  @id @default(cuid())\n  name           String\n  email          String  @unique\n  password       String? // For dashboard login\n  phone          String?\n  youtubeUrl     String?\n  instagramUrl   String?\n  code           String? @unique // Nullable for pending requests\n  commissionRate Float   @default(10.0)\n  totalSales     Float   @default(0)\n  totalEarnings  Float   @default(0)\n  payoutInfo     String? @default(\"\")\n  status         String  @default(\"pending\") // pending, approved, rejected, inactive\n\n  orders    Order[] // Orders referred by this affiliate\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n///////////////////////\n// 🏠 ADDRESS\n///////////////////////\nmodel Address {\n  id       String @id @default(cuid())\n  fullName String\n  phone    String\n  city     String\n  state    String\n  pincode  String\n  address  String\n\n  orderId String @unique\n  order   Order  @relation(fields: [orderId], references: [id])\n}\n\n///////////////////////\n// 🎁 OFFERS / COUPONS\n///////////////////////\nmodel Coupon {\n  id           String @id @default(cuid())\n  code         String @unique // The coupon code entered by the user\n  discountType String // 'PERCENTAGE', 'FIXED_AMOUNT', 'BOGO', 'FREE_SHIPPING', 'BEHAVIORAL', 'BANK_OFFER'\n\n  // Values\n  discountValue Float? // Amount or Percentage. (e.g. 20 for 20%, or 500 for ₹500)\n  description   String? // e.g. \"Flat 20% Off\", \"Buy 2 Get 1 Free\"\n\n  // Constraints\n  minPurchase Float? // e.g. \"₹300 off on orders above ₹1500\"\n  maxDiscount Float? // e.g. \"Upto ₹1000 Off\"\n\n  // BOGO / Bundle\n  buyQuantity Int? // e.g. Buy 2\n  getQuantity Int? // e.g. Get 1\n  isBundle    Boolean @default(false)\n\n  // Advanced Routing\n  targetCustomer String? @default(\"ALL\") // 'ALL', 'NEW_USER', 'ABANDONED_CART'\n  bankName       String? // e.g. 'HDFC', 'SBI'\n\n  // Limits\n  expiresAt  DateTime?\n  usageLimit Int?\n  usedCount  Int       @default(0)\n\n  active    Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n///////////////////////\n// 📑 STATIC CONTENT\n///////////////////////\n// 📑 CUSTOM PAGES (Builder)\n///////////////////////\nmodel Page {\n  id        String   @id @default(cuid())\n  title     String\n  slug      String   @unique\n  active    Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sections PageSection[]\n}\n\nmodel PageSection {\n  id      String  @id @default(cuid())\n  type    String // 'hero', 'about', 'products', 'text', 'instagram', 'features'\n  content Json // Stores all section-specific data (title, images, etc.)\n  order   Int     @default(0)\n  active  Boolean @default(true)\n\n  pageId String\n  page   Page   @relation(fields: [pageId], references: [id], onDelete: Cascade)\n}\n\n// Keep Content for backward compatibility or simple one-off blocks\nmodel Content {\n  id    String @id @default(cuid())\n  title String\n  body  String\n}\n\n///////////////////////\n// ⚙️ STORE SETTINGS\n///////////////////////\nmodel StoreSettings {\n  id                 String  @id @default(\"global\") // Keep a single row\n  razorpayKeyId      String?\n  razorpaySecret     String?\n  shiprocketEmail    String?\n  shiprocketPassword String?\n}\n\n///////////////////////\n// 🛒 ABANDONED CHECKOUTS\n///////////////////////\nmodel AbandonedCheckout {\n  id        String  @id @default(cuid())\n  email     String?\n  phone     String?\n  firstName String?\n  lastName  String?\n  address   String?\n  apartment String?\n  city      String?\n  state     String?\n  pincode   String?\n\n  cartItems      Json // Stores items as {id, title, price, quantity, image}[]\n  total          Float\n  discountAmount Float   @default(0)\n  couponCode     String?\n\n  recoveryToken String @unique @default(cuid())\n  lastStep      String @default(\"contact\") // 'contact', 'delivery', 'payment'\n\n  remindersSent    Int       @default(0)\n  lastReminderSent DateTime?\n\n  recovered   Boolean   @default(false)\n  recoveredAt DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
  "inlineSchemaHash": "fa1db8195ff87b63100722f4351b94bb38821930d6460c26d5732dc9e1e193b5",
